    const uint32_t N    = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t C_in = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t H    = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t W    = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));
    const uint32_t C_out= static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));
    const uint32_t Cin_w= static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(1));

