#include "kernel_operator.h"

constexpr int32_t X_BUF_NUM = 1;

class KernelConvPointwise2dCustom {
public:
    __aicore__ inline KernelConvPointwise2dCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR w, GM_ADDR y,
                                uint32_t N, uint32_t CIn, uint32_t H, uint32_t W,
                                uint32_t COut, uint32_t tilePixels)
    {
        n_ = N;
        cin_ = CIn;
        h_ = H;
        w_ = W;
        cout_ = COut;
        tilePix_ = tilePixels;

        uint64_t xTotal = static_cast<uint64_t>(N) * CIn * H * W;
        uint64_t yTotal = static_cast<uint64_t>(N) * COut * H * W;
        uint64_t wTotal = static_cast<uint64_t>(COut) * CIn;

        xGm_.SetGlobalBuffer((__gm__ float*)x, xTotal);
        wGm_.SetGlobalBuffer((__gm__ float*)w, wTotal);
        yGm_.SetGlobalBuffer((__gm__ float*)y, yTotal);

        // Buffers: wLocal (COut*CIn), yTile (tilePix*COut), xVec (tilePix), tmp (tilePix)
        pipe_.InitBuffer(wQueue_, 1, cout_ * cin_ * sizeof(float));
        pipe_.InitBuffer(yQueue_, 1, tilePix_ * cout_ * sizeof(float));
        pipe_.InitBuffer(xQueue_, X_BUF_NUM, tilePix_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tilePix_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (n_ == 0 || cin_ == 0 || cout_ == 0 || h_ == 0 || w_ == 0 || tilePix_ == 0) return;

        const uint32_t HW = h_ * w_;
        const uint64_t totalPix = static_cast<uint64_t>(n_) * HW;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Preload weights once into UB
        AscendC::LocalTensor<float> wLocal = wQueue_.AllocTensor<float>();
        AscendC::DataCopy(wLocal, wGm_[0], static_cast<uint32_t>(cout_ * cin_));
        // Create yTile buffer (allocated once, reused per tile)
        AscendC::LocalTensor<float> yTile = yQueue_.AllocTensor<float>();

        const uint64_t stride = static_cast<uint64_t>(blockNum) * tilePix_;
        uint64_t basePix = static_cast<uint64_t>(blockIdx) * tilePix_;
        while (basePix < totalPix) {
            // Compute n and in-plane offset; constrain tile not to cross N boundary
            const uint32_t n = static_cast<uint32_t>(basePix / HW);
            const uint32_t hwOff = static_cast<uint32_t>(basePix - static_cast<uint64_t>(n) * HW);
            uint32_t curLen = tilePix_;
            if (hwOff + curLen > HW) curLen = HW - hwOff;

            // Zero yTile for [curLen, COut]
            AscendC::Dup(yTile, 0.0f, static_cast<uint32_t>(curLen * cout_));

            // Accumulate over input channels
            for (uint32_t ci = 0; ci < cin_; ++ci) {
                // Load x vector slice (contiguous within one image plane)
                const uint64_t xBase = (static_cast<uint64_t>(n) * cin_ + ci) * HW + hwOff;
                AscendC::LocalTensor<float> xVec = xQueue_.AllocTensor<float>();
                AscendC::DataCopy(xVec, xGm_[xBase], curLen);

                // For each output channel, y[:,co] += xVec * w[co,ci]
                for (uint32_t co = 0; co < cout_; ++co) {
                    const float wcoef = wLocal[co * cin_ + ci];
                    AscendC::LocalTensor<float> tmp = tmpQueue_.AllocTensor<float>();
                    AscendC::Muls(tmp, xVec, wcoef, curLen);
                    AscendC::LocalTensor<float> ySeg = yTile[co * tilePix_];
                    AscendC::Add(ySeg, ySeg, tmp, curLen);
                    tmpQueue_.FreeTensor(tmp);
                }

                xQueue_.FreeTensor(xVec);
            }

            // Store yTile to GM per output channel
            for (uint32_t co = 0; co < cout_; ++co) {
                const uint64_t yBase = (static_cast<uint64_t>(n) * cout_ + co) * HW + hwOff;
                AscendC::LocalTensor<float> ySeg = yTile[co * tilePix_];
                AscendC::DataCopy(yGm_[yBase], ySeg, curLen);
            }

            basePix += stride;
        }

        // Free persistent local buffers
        yQueue_.FreeTensor(yTile);
        wQueue_.FreeTensor(wLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> wQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> yQueue_;
    AscendC::TQue<AscendC::TPosition::VECIN, X_BUF_NUM> xQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t n_{0};
    uint32_t cin_{0};
    uint32_t h_{0};
    uint32_t w_{0};
    uint32_t cout_{0};
    uint32_t tilePix_{0};
};

extern "C" __global__ __aicore__ void conv_pointwise_2d_custom(GM_ADDR x, GM_ADDR weight, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelConvPointwise2dCustom op;
    op.Init(x, weight, y,
            tiling_data.n, tiling_data.cIn, tiling_data.h, tiling_data.w,
            tiling_data.cOut, tiling_data.tilePixels);
    op.Process();
}
